import React from "react";
import { Helmet } from "react-helmet";
import * as seo from "../constants/SEO";

const Seo = ({ title, meta, description }) => {
  return (
    <Helmet
      htmlAttributes={{
        lang: seo.lang,
      }}
      title={title}
      titleTemplate={`%s | ${seo.baseTitle}`}
      meta={[
        {
          name: `description`,
          content: description,
        },
        {
          property: `og:title`,
          content: title,
        },
        {
          property: `og:description`,
          content: description,
        },
        {
          property: `og:type`,
          content: `website`,
        },
        {
          name: `twitter:card`,
          content: `summary`,
        },
        {
          name: `twitter:creator`,
          content: description,
        },
        {
          name: `twitter:title`,
          content: title,
        },
        {
          name: `twitter:description`,
          content: description,
        },
      ].concat(meta)}
    />
  );
};

Seo.defaultProps = {
  lang: `en`,
  meta: [],
  description: seo.metaDescription,
};

export default Seo;
